arguments.file_text:
@typeparam TItem

@if (_items.Count > 0)
{
    <table>
        <thead>
            <tr>
                @HeaderTemplate
            </tr>
        </thead>
        <tbody>
            @foreach (var item in _items)
            {
                <tr @key="item" @onclick="() => OnRowClick.InvokeAsync(item)">
                    @RowTemplate(item)
                </tr>
            }
        </tbody>
    </table>
}
else
{
    @if (EmptyTemplate is not null)
    {
        @EmptyTemplate
    }
    else
    {
        <p>No items to display.</p>
    }
}

@code {
    private IReadOnlyList<TItem> _items = Array.Empty<TItem>();

    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = Array.Empty<TItem>();

    [Parameter, EditorRequired]
    public RenderFragment HeaderTemplate { get; set; } = default!;

    [Parameter, EditorRequired]
    public RenderFragment<TItem> RowTemplate { get; set; } = default!;

    [Parameter]
    public RenderFragment? EmptyTemplate { get; set; }

    [Parameter]
    public EventCallback<TItem> OnRowClick { get; set; }

    protected override void OnParametersSet()
    {
        _items = Items ?? Array.Empty<TItem>();
    }
}

